class Solution {
    public int racecar(int target) {
        Queue<int[]> q = new LinkedList<>();
        q.offer(new int[]{0, 1});
        boolean[] visited = new boolean[target * 2 + 1];
        visited[1] = true;
        int step = 0;
        while (!q.isEmpty()) {
            int size = q.size();
            for (int i = 0; i < size; i++) {
                int[] state = q.poll();
                if (state[0] == target) return step;
                int[] nextA = new int[]{state[0] + state[1], state[1] * 2};
                if (nextA[0] <= target * 2 && !visited[nextA[1]]) {
                    q.offer(nextA);
                    visited[nextA[1]] = true;
                }
                int[] nextR = new int[]{state[0], state[1] > 0 ? -1 : 1};
                if (!visited[nextR[1]]) {
                    q.offer(nextR);
                    visited[nextR[1]] = true;
                }
            }
            step++;
        }
        return -1;
    }
}
